    "text": "大丈夫、さくら?"
  },
  {
    "id": 574,
    "text": "やばい、やばい、やばい、やばい。"
  },
  {
    "id": 575,
    "text": "さく、さくびっくり今私。"
  },
  {
    "id": 576,
    "text": "なんでこっち側に回ると思ってなかったよ。"
  },
  {
    "id": 577,
    "text": "なんかいつの間にさくらそんな感じになっちゃったと思って今。"
  },
  {
    "id": 578,
    "text": "心配されてるよ。"
  },
  {
    "id": 579,
    "text": "ツッコミ側思い浮かばなくて、だったら乗っちゃおうかなと思ってどっちかにね。"
  },
  {
    "id": 580,
    "text": "素晴らしい。"
  },
  {
    "id": 581,
    "text": "そうそう素晴らしい。"
  },
  {
    "id": 582,
    "text": "籔島がめちゃ困惑してたからね、今ね。"
  },
  {
    "id": 583,
    "text": "さ、さくが心配された。"
  },
  {
    "id": 584,
    "text": "心配される一番恥ずかしいやつ。"
  },
  {
    "id": 585,
    "text": "いや、どうでした、どうでした今日?"
  },
  {
    "id": 586,
    "text": "いや、なんかめちゃめちゃすごい感想詳しく、詳しくというか、あの、たくさん話させていただいて、"
  },
  {
    "id": 587,
    "text": "いい、いいんですかね?"
  },
  {
    "id": 588,
    "text": "ありがとうございます。"
  },
  {
    "id": 589,
    "text": "みんな聞きたかったね。"
  },
  {
    "id": 590,
    "text": "来週も話しますから。"
  },
  {
    "id": 591,
    "text": "そうですよ。"
  },
  {
    "id": 592,
    "text": "はい。"
  },
  {
    "id": 593,
    "text": "いつまで7の話をね、していいんだろうかな。"
  },
  {
    "id": 594,
    "text": "大体3年間ぐらいっていうの予定しておりまして、大体ね、はい。"
  },
  {
    "id": 595,
    "text": "全曲終わるまでやりますから。"
  },
  {
    "id": 596,
    "text": "あ、全曲やりますよ、じゃ。"
  },
  {
    "id": 597,
    "text": "チームライブできないじゃん、もう。"
  },
  {
    "id": 598,
    "text": "分からないです。"
  },
  {
    "id": 599,
    "text": "押します。"
  },
  {
